import React from 'react';
import PageLogo from '../Logo/GnuLinuxLogo.svg';
import HeaderInfoBackgroundImage from '../Background/HeaderInfoBackgroundImage.jpg';
import HeaderInfoGitHubLogo from '../Logo/GitHubLogo.svg';
import HeaderInfoGitHubPagesLogo from '../Logo/GitHubPagesLogo.svg';

import '../HeaderInfo.css';

class HeaderInfo extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      domainLogo: props.domainLogo || PageLogo,
      currentPageName: props.currentPageName || '',
      backgroundImage: props.backgroundImage || HeaderInfoBackgroundImage,
      githubLogo: props.githubLogo || HeaderInfoGitHubLogo,
      githubPagesLogo: props.githubLogo || HeaderInfoGitHubPagesLogo,
      githubURL: props.githubURL || "www.github.com",
      githubPagesURL: props.githubPagesURL || "www.github.com",
      domainName: props.domainName || "www.unix69.githubio.com",
      pageName: props.pageName || "Unix69",

      headerTitleInfoClass: props.headerTitleInfoClass || "header-title-info",
      headerTitleInfoBackgroundImageClass: props.headerTitleInfoBackgroundImageClass || "header-title-info-background-image",
      headerTitleInfoDomainInfoClass: props.headerTitleInfoClass || "header-title-info-domain-info",
      headerTitleInfoDomainUrlClass: props.headerTitleInfoDomainUrlClass || "header-title-info-domain-url",
      headerTitleInfoDomainLogoClass: props.headerTitleInfoDomainLogoClass || "header-title-info-domain-logo",

      headerMainInfoClass: props.headerTitleInfoClass || "header-main-info",
      headerMainInfoCurrentPageClass: props.headerMainInfoCurrentPageClass ||  "header-main-info-current-page",
      headerMainInfoSpaceClass: props.headerMainInfoSpaceClass || "header-main-info-space",
      headerMainInfoGitHubInfoClass: props.headerMainInfoGitHubInfoClass || "header-main-info-github-info",
      headerMainInfoGitHubUrlClass: props.headerMainInfoGitHubUrlClass || "header-main-info-github-url",
      headerMainInfoGitHubPagesUrlClass: props.headerMainInfoGitHubPagesUrlClass || "header-main-info-github-pages-url",
      headerMainInfoGitHubLogoClass: props.headerMainInfoGitHubLogoClass || "header-main-info-github-logo",
      headerMainInfoGitHubPagesLogoClass: props.headerMainInfoGitHubPagesLogoClass || "header-main-info-github-pages-logo",

      headerSubInfoClass: props.headerSubInfoClass || "header-sub-info"

    };
  }

  render() {
    return (<section>
              <div class={this.state.headerTitleInfoClass}>
                <img src={this.state.domainLogo} alt="Domain Logo" className={this.state.headerTitleInfoDomainLogoClass}/>
                <a href={this.state.domainName} class={this.state.headerTitleInfoDomainUrlClass}>{this.state.pageName}</a>
              </div>


              <div class={this.state.headerMainInfoClass}>
                <div class={this.state.headerMainInfoCurrentPageClass}>{this.state.currentPageName}</div>
                <div class={this.state.headerMainInfoSpaceClass}/>
                <div class={this.state.headerMainInfoGitHubInfoClass}>                 
                  <a href={this.state.githubURL} class={this.state.headerMainInfoGitHubUrlClass}>
                    <img src={this.state.githubLogo} alt="GitHub Logo" class={this.state.headerMainInfoGitHubLogoClass}/>
                  </a>


                  <a href={this.state.githubPagesURL} class={this.state.headerMainInfoGitHubPagesUrlClass}>
                    <img src={this.state.githubPagesLogo} alt="GitHub Pages Logo" class={this.state.headerMainInfoGitHubPagesLogoClass}/>
                  </a>

                </div>
              </div>

              <div class={this.state.headerSubInfoClass}>

              </div>




            </section>
    );
  }
}

export default HeaderInfo;
